// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.equivalence.internal;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertNotEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.List;
import java.util.Set;

import org.eclipse.rdf4j.query.algebra.Lateral;
import org.eclipse.rdf4j.query.algebra.SingletonSet;
import org.junit.jupiter.api.Test;

class CanonicalOrderingTest {

	@Test
	void unequalCandidatesWithTheSameOrderingKeyAreRejected() {
		CanonicalNode oneName = CanonicalNode.opaque(
				new Lateral(new SingletonSet(), new SingletonSet(), Set.of("left,right")));
		CanonicalNode twoNames = CanonicalNode.opaque(
				new Lateral(new SingletonSet(), new SingletonSet(), Set.of("left", "right")));

		assertEquals(0, oneName.compareTo(twoNames));
		assertNotEquals(oneName, twoNames);
		List<Rdf4jCanonicalizer.NormalizationCandidate> candidates = List.of(
				new Rdf4jCanonicalizer.NormalizationCandidate(oneName, List.of()),
				new Rdf4jCanonicalizer.NormalizationCandidate(twoNames, List.of()));
		assertTrue(Rdf4jCanonicalizer.unambiguousMinimum(candidates).isEmpty());
	}
}
